==A new production incident has broken out. Execute high-tier data triage operations immediately.

Incident ID: {{ $json.incident_id }}
Trigger Source: {{ $json.source }}
Timestamp: {{ $json.timestamp }}

RAW LOG DATA ENVELOPE:
----------------------------------------
{{ $json.raw_log }}
----------------------------------------

Analyze the envelope data, isolate structural parameters, and output the normalized JSON block matching the mandatory schema.

parameters.jsCode:
// Ensure we handle whatever item comes through the active execution stream
const items = $input.all();
let outputItem = {};

try {
    // 1. Check if we are on the Error Track (Incoming data from the Error Informer node)
    const errorInformerNode = $('Error informer') ?.item ?.json;
    const isExplicitErrorTrack = !!errorInformerNode;

    // 2. Extract Inspector data if it executed successfully
    let inspectorData = null;
    try {
        inspectorData = $('Inspector') ?.item ?.json;
    } catch (e) {
        // Inspector node skipped or failed completely
    }

    // Determine if the pipeline failed validation or ran into a system error
    if (isExplicitErrorTrack || !inspectorData || inspectorData.passed_inspection === false) {
        // BUILD ACCELERATED ERROR PACKET
        outputItem = {
            status: "error",
            timestamp: new Date().toISOString(),
            error_details: {
                type: errorInformerNode?.isolated_exception || "PIPELINE_VALIDATION_FAILURE",
                summary: errorInformerNode?.root_cause_summary || inspectorData?.override_notes || "The Triage Inspector failed validation rules due to swarm conflicts.",
                raw_payload: errorInformerNode?.raw_telemetry_payload || JSON.stringify(inspectorData) || "No raw telemetry provided."
            }
        };
    } else {
        // BUILD ENTERPRISE SUCCESS PACKET
        const devNode = $('Hardcore Developer').item.json;
        const securityNode = $('Risk Evaluator').item.json;
        const prNode = $('PR & Status Manager').item.json;

        // Grab passing incident parameters safely
        const baseTrigger = $input.item.json; 

        outputItem = {
            status: "success",
            incident_id: baseTrigger?.incident_id || "INC-" + Math.floor(Math.random() * 100000),
            timestamp: new Date().toISOString(),

            // Aggregated Swarm Intelligence
            diagnostics: {
                classification: baseTrigger?.triage_metadata?.classification || "UNKNOWN",
                root_cause: devNode?.root_cause || "No code diagnostics provided.",
                proposed_patch: devNode?.proposed_patch || "// Code patch unavailable.",
                security_risk_score: securityNode?.risk_score || 0,
                security_cve: securityNode?.cve_reference || "N/A",
                security_containment: securityNode?.containment_protocol || "No containment available.",
                communications_slack: prNode?.internal_slack_markdown || "",
                communications_public: prNode?.public_status_page || ""
            },

            // Metas & Validation Data
            pipeline_metrics: {
                inspector_summary: inspectorData?.evaluation_summary || "Passed manual inspection.",
                dev_confidence: devNode?.confidence_score || 0,
                security_confidence: securityNode?.confidence_score || 0,
                pr_confidence: prNode?.confidence_score || 0
            },

            // METRIC PAYLOAD FOR DASHBOARD ENGINE (GRAFANA/INFLUX)
            grafana_metrics: {
                measurement: "production_incidents",
                tags: {
                    status: "resolved_triage",
                    classification: baseTrigger?.triage_metadata?.classification || "GENERAL_BUG",
                    cve_linked: (securityNode?.cve_reference !== "N/A") ? "true" : "false"
                },
                fields: {
                    risk_score: Number(securityNode?.risk_score || 0),
                    dev_confidence: Number(devNode?.confidence_score || 0),
                    security_confidence: Number(securityNode?.confidence_score || 0),
                    pipeline_passed: 1
                }
            }
        };
    }
} catch (globalError) {
    // Ultimate Fallback to keep n8n from completely freezing if the JS layer breaks
    outputItem = {
        status: "error",
        timestamp: new Date().toISOString(),
        error_details: {
            type: "AGGREGATOR_CRITICAL_EXCEPTIONAL_CRASH",
            summary: "The Aggregator JavaScript node experienced a parsing execution failure.",
            raw_payload: globalError.message
        }
    };
}

return [{ json: outputItem }];

const items = $input.all();
const result = [];

for (const item of items) {
  let rawLog = "";
  let source = "Unknown Trigger";

  // Case A: Triggered via Production Webhook
  if (item.json.body) {
    rawLog = typeof item.json.body === 'object' ? JSON.stringify(item.json.body, null, 2) : item.json.body;
    source = "Production Webhook Fire Alarm";
  } 
  // Case B: Triggered via Automated Prompt / Schedule Node
  else if (item.json.myCustomPrompt || item.json.text) {
    rawLog = item.json.myCustomPrompt || item.json.text;
    source = "Scheduled Morning Audit";
  } 
  // Case C: Fallback / Test Execution
  else {
    rawLog = Object.keys(item.json).length > 0 ? JSON.stringify(item.json, null, 2) : "No log provided. System testing sequence initiated.";
    source = "Manual/Test Sandbox Trigger";
  }

  result.push({
    json: {
      incident_id: "INC-" + Math.floor(100000 + Math.random() * 900000),
      timestamp: new Date().toISOString(),
      source: source,
      raw_log: rawLog
    }
  });
}

return result;

