parameters.jsCode:
const item = $input.item.json;
const isSuccess = (item.status === "success");

let slack = "";
let gmail = "";
let discord = {};
let github = {};
let telegram = "";
let google_sheets = {};

if (isSuccess) {
    // 🟢 BUILD SUCCESS DELIVERABLES
    const d = item.diagnostics;
    const m = item.pipeline_metrics;

    // Slack Markdown Payload
    slack = d.communications_slack + `\n\n*Pipeline Health Info:* Dev Confidence: \`${m.dev_confidence}\` | Sec Confidence: \`${m.security_confidence}\``;

    // Gmail Beautiful HTML Template
    gmail = `
    <div style="font-family: Arial, sans-serif; max-width: 600px; border: 1px solid #1a3322; border-radius: 8px; padding: 20px;">
        <h2 style="color: #2e7d32; border-bottom: 2px solid #2e7d32; padding-bottom: 5px;">🟢 Production Incident Mitigated [${item.incident_id}]</h2>
        <p><strong>Classification:</strong> ${d.classification}</p>
        <p><strong>Root Cause Analysis:</strong></p>
        <blockquote style="background: #f1f8e9; padding: 10px; border-left: 4px solid #8bc34a;">${d.root_cause}</blockquote>
        <p><strong>Proposed Source Remediation:</strong></p>
        <pre style="background: #272727; color: #a6e22e; padding: 12px; border-radius: 4px; overflow-x: auto;"><code>${d.proposed_patch}</code></pre>
        <p><strong>Security Protocols Activated [Risk Score: ${d.security_risk_score}]:</strong></p>
        <p style="color: #c62828;">${d.security_containment}</p>
        <p style="font-size: 11px; color: #777;">Triage System Token Authentication Key: ${item.timestamp}</p>
    </div>`;

    // Discord Rich Embed Object
    discord = {
        content: `🚨 **Incident Resolved & Triaged: ${item.incident_id}**`,
        embeds: [{
            title: `Classification: ${d.classification}`,
            description: d.communications_public,
            color: 3066993, // Green
            fields: [
                { name: "Risk Assessment Score", value: `${d.security_risk_score}/10`, inline: true },
                { name: "Linked CVE Matrix", value: d.security_cve, inline: true }
            ]
        }]
    };

    // GitHub Issue Formatter
    github = {
        title: `[Triage-Autofix] Production Incident ${item.incident_id} - ${d.classification}`,
        body: `### Technical Diagnostics\n\n**Root Cause:**\n${d.root_cause}\n\n### Proposed Code Patch\n\`\`\`javascript\n${d.proposed_patch}\n\`\`\`\n\n### Security Containment\n${d.security_containment}`
    };

    // Telegram Compact Emojis
    telegram = `🟢 *INCIDENT TRIAGED: ${item.incident_id}*\n\n• Type: ${d.classification}\n• Risk Score: ${d.security_risk_score}/10\n• Status: Public status page updated successfully. Check engineering channels for the hot patch.`;

    // Google Sheets Row Flattener
    google_sheets = {
        incident_id: item.incident_id,
        status: "SUCCESS_TRIAGED",
        timestamp: item.timestamp,
        classification: d.classification,
        risk_score: d.security_risk_score,
        patch_provided: d.proposed_patch ? "YES" : "NO",
        error_log_summary: "N/A"
    };

} else {
    // 🔴 BUILD FAILURE / ERROR DELIVERABLES
    const err = item.error_details;

    slack = `🚨 *CRITICAL: DevSecOps Triage Engine Outage!*\n• *Type:* \`${err.type}\`\n• *Summary:* ${err.summary}\n• *Raw Data:* \`${err.raw_payload}\``;

    gmail = `
    <div style="font-family: Arial, sans-serif; max-width: 600px; border: 1px solid #b71c1c; border-radius: 8px; padding: 20px;">
        <h2 style="color: #c62828; border-bottom: 2px solid #c62828; padding-bottom: 5px;">🔴 Automated Triage Pipeline Outage</h2>
        <p style="color: #b71c1c;"><strong>Critical Error Intercepted inside the n8n Core Layer.</strong></p>
        <p><strong>Exception Pattern:</strong> ${err.type}</p>
        <p><strong>Operational Impact:</strong> ${err.summary}</p>
        <p><strong>Raw Diagnostics:</strong></p>
        <pre style="background: #f5f5f5; color: #333; padding: 10px; border: 1px dashed #ccc;">${err.raw_payload}</pre>
    </div>`;

    discord = {
        content: `💥 **CRITICAL SYSTEM ALERT: Automation Pipeline Broken**`,
        embeds: [{
            title: `Pipeline Exception: ${err.type}`,
            description: err.summary,
            color: 15158332, // Red
            fields: [{ name: "Raw Trace", value: err.raw_payload.substring(0, 1024) }]
        }]
    };

    github = {
        title: `[URGENT OMNI-CRASH] DevSecOps Engine Failure - ${err.type}`,
        body: `The autonomous triage agent network encountered a fatal execution roadblock.\n\n**Reason:** ${err.summary}\n\n**Raw Stack Tracking:**\n\`\`\`text\n${err.raw_payload}\n\`\`\``
    };

    telegram = `🔴 *PIPELINE OUTAGE ALERT*\n\nAn engineering exception broke the automation framework.\n• *Error:* ${err.type}\n• *Details:* ${err.summary}`;

    google_sheets = {
        incident_id: "ERR-" + Math.floor(Math.random() * 100000),
        status: "PIPELINE_CRASHED",
        timestamp: item.timestamp,
        classification: "N/A",
        risk_score: 10, // Max alert for system crashes
        patch_provided: "NO",
        error_log_summary: err.summary
    };
}

// Package everything cleanly into a standardized output interface
return [{
    json: {
        meta_status: item.status,
        app_targets: {
            slack_message: slack,
            gmail_html_body: gmail,
            discord_embed: discord,
            github_issue_data: github,
            telegram_text: telegram,
            google_sheets_row: google_sheets
        }
    }
}];

